import React from 'react';
import { ArrowUpRight, Cpu } from 'lucide-react';

export default function Navbar() {
    return (
        <nav className="fixed top-0 left-0 right-0 z-50 border-b border-zinc-900 bg-[#030303]/70 backdrop-blur-md px-6 py-4">
            <div className="max-w-7xl mx-auto flex items-center justify-between">
                <div className="flex items-center gap-2 font-semibold text-white tracking-tight cursor-pointer">
                    <Cpu className="w-5 h-5 text-purple-500 animate-pulse" />
                    <span>Aether.AI</span>
                </div>
                <div className="hidden md:flex items-center gap-8 text-sm text-zinc-400">
                    <a href="#features" className="hover:text-white transition-colors">Features</a>
                    <a href="#pricing" className="hover:text-white transition-colors">Pricing</a>
                    <a href="#faq" className="hover:text-white transition-colors">FAQ</a>
                </div>
                <div>
                    <button className="flex items-center gap-1.5 px-4 py-2 rounded-lg bg-zinc-950 border border-zinc-800 text-xs font-medium text-zinc-200 hover:bg-zinc-900 hover:text-white transition-all active:scale-95">
                        Get Started
                        <ArrowUpRight className="w-3.5 h-3.5" />
                    </button>
                </div>
            </div>
        </nav>
    );
}